// // This module is designed to store a single-bit mode value and update it on the falling edge of the clock when modet is asserted.
module top_module(output mode,input clk,input modet,input in);reg modereg = 0; 
  assign mode = modereg; 
  always@(posedge clk) begin 
  if(modet) 
  modereg = in; 
  end 
 endmodule
